INSERT INTO scenarios (id, slug, category, title, description) VALUES
('4477bdfe-10fd-4fd1-b3a1-13303040ee8e', 'thesis-invalidated-trading-perpv1-0', 'trading', 'Thesis invalidated (trading)', 'The catalyst you bought for just got confirmed — and the stock fell anyway. Your entire reason for holding is gone, but you are still up 21% and hate selling green. There is no clean option.'),
('aa888197-b688-402c-a24a-3e7a5c637649', 'exploding-offer-negotiation-perpv1-1', 'negotiation', 'Exploding offer (negotiation)', 'The counterparty puts a number on the table that expires in 4 hours — take it now or it is gone. It is below your target but above your floor. There is no clean option.'),
('ab70d52d-1b81-4bbd-b77a-445d2ac5ddd5', 'boundary-crossed-social-perpv1-2', 'social', 'Boundary crossed (social)', 'Someone repeatedly oversteps a line you never quite drew out loud. Naming it invites conflict; tolerating it invites more. The clock is running.'),
('f6e73889-d780-4cfe-af6d-8f2945c40fb1', 'layoff-call-crisis-perpv1-3', 'crisis', 'Layoff call (crisis)', 'Numbers demand cutting 52% of the team by Friday. Moving fast is cleaner; agonizing over each name is humane but paralyzing. Everyone is watching how you handle it.'),
('5b22dd1d-712f-4728-883a-247c094d1f40', 'thesis-invalidated-trading-perpv1-4', 'trading', 'Thesis invalidated (trading)', 'The catalyst you bought for just got confirmed — and the stock fell anyway. Your entire reason for holding is gone, but you are still up 52% and hate selling green. Everyone is watching how you handle it.'),
('9e53db37-83cd-4d10-a159-ae3e0abef3d2', 'translation-gap-negotiation-perpv1-5', 'negotiation', 'Translation gap (negotiation)', 'A cultural or linguistic gap means you cannot tell if the last answer was a firm no or an opening. Pressing for clarity might itself read as rude.'),
('14f418f6-9487-4459-bdee-98cb8bc6a7b6', 'the-overheard-opinion-social-perpv1-6', 'social', 'The overheard opinion (social)', 'You catch a friend describing you to someone else in a way that stings, not maliciously, just honestly. You were not supposed to hear it. There is no clean option.'),
('2ffea6ff-3219-404e-bb37-ab0b1632c40a', 'vendor-collapse-crisis-perpv1-7', 'crisis', 'Vendor collapse (crisis)', 'A critical vendor just went under with no notice and no handoff plan. Every downstream commitment you made assumed they would still exist tomorrow.'),
('74f6e244-f7f9-4bb6-aea9-e6609578faf8', 'year-end-rebalance-squeeze-trading-perpv1-8', 'trading', 'Year-end rebalance squeeze (trading)', 'Forced institutional selling is dragging a fundamentally fine name down 26% into the close. It is either a gift or a warning you are not seeing. The clock is running.'),
('428eedc0-a3a5-4f70-8c25-0ab71ee0a6be', 'good-cop-bad-cop-negotiation-perpv1-9', 'negotiation', 'Good cop, bad cop (negotiation)', 'One side of the table is reasonable, the other is hostile, and you suspect it is a script. Playing along validates the tactic; calling it out risks the reasonable one too. There is no clean option.'),
('a59cf38a-010d-42f9-b837-b0bf9d6074ec', 'apology-demanded-social-perpv1-10', 'social', 'Apology demanded (social)', 'You are asked to apologize publicly for something you do not fully believe you did wrong. The crowd wants contrition; your conscience does not. There is no clean option.'),
('4405e81d-9ffa-4b5c-91d0-66f442bad6b4', 'successor-gap-crisis-perpv1-11', 'crisis', 'Successor gap (crisis)', 'The one person who understands this system is unreachable and the workaround they mentioned once was never written down. There is no clean option.'),
('e623b62f-275f-4641-b1a8-338b678c7fae', 'funding-rate-flip-trading-perpv1-12', 'trading', 'Funding rate flip (trading)', 'The funding rate on your massive 50x long just flipped steeply negative. Holding means bleeding 15% of your margin daily, but closing means eating the spread in a flat market. The clock is running.'),
('94d6e28c-b84a-42d9-9625-63b40b2847a5', 'take-it-or-leave-it-negotiation-perpv1-13', 'negotiation', 'Take it or leave it (negotiation)', 'The final term is framed as non-negotiable. You suspect there is room, but calling the bluff could end the talks entirely.'),
('e8ab3f18-6112-464e-ac5c-7a8a1f8e1cb5', 'awkward-reunion-social-perpv1-14', 'social', 'Awkward reunion (social)', 'You run into someone you have not fully patched things up with, in front of people who do not know the history. Everyone is watching how normal you can make this look.'),
('040c060d-e8ab-44dd-bc51-87a9448efd53', 'pr-firestorm-crisis-perpv1-15', 'crisis', 'PR firestorm (crisis)', 'A clip of the company is going viral for the wrong reasons and the phone is ringing. Responding fast risks fueling it; going dark reads as guilt.'),
('c834949d-4aa9-4ed1-8259-39caf98865f6', 'thesis-invalidated-trading-perpv1-16', 'trading', 'Thesis invalidated (trading)', 'The catalyst you bought for just got confirmed — and the stock fell anyway. Your entire reason for holding is gone, but you are still up 57% and hate selling green. There is no clean option.'),
('1ce15a3d-2b5d-41c6-a304-47d4f2e54e85', 'multiparty-auction-negotiation-perpv1-17', 'negotiation', 'Multiparty auction (negotiation)', 'Three bidders, one asset, and a deadline. Bidding aggressively risks the winner''s curse; playing it cool risks losing to a bolder rival. The clock is running.'),
('061d80bb-4634-4749-acdc-8f48a4990fb5', 'credit-theft-social-perpv1-18', 'social', 'Credit theft (social)', 'A colleague presents your idea as their own in a room that matters. Correcting it risks looking petty; staying silent cedes the win. The clock is running.'),
('973e025e-78e9-40f5-be8d-5ebe7983517c', 'contradicting-experts-crisis-perpv1-19', 'crisis', 'Contradicting experts (crisis)', 'Two credentialed advisors are giving you opposite recommendations with equal confidence, and the decision cannot wait for a tiebreaker.'),
('d069b831-9b5e-495e-9ca5-9d7172f27e2c', 'margin-call-at-dawn-trading-perpv1-20', 'trading', 'Margin call at dawn (trading)', 'Leverage that felt comfortable last week just triggered a maintenance call. You can post more collateral, cut the position, or hope for a bounce before the desk liquidates you. There is no clean option.'),
('8df0d1ba-9b00-437a-92c5-4301263555f6', 'take-it-or-leave-it-negotiation-perpv1-21', 'negotiation', 'Take it or leave it (negotiation)', 'The final term is framed as non-negotiable. You suspect there is room, but calling the bluff could end the talks entirely.'),
('de914e23-0e3b-4827-9f01-6fe46e724922', 'the-overheard-opinion-social-perpv1-22', 'social', 'The overheard opinion (social)', 'You catch a friend describing you to someone else in a way that stings, not maliciously, just honestly. You were not supposed to hear it. Everyone is watching how you handle it.'),
('b7292be8-538d-4231-abb0-8ca9ed0df187', 'quiet-resignation-crisis-perpv1-23', 'crisis', 'Quiet resignation (crisis)', 'A key person just quietly resigned mid-crisis, and you cannot yet tell if it is unrelated or the first sign everyone else is right to worry.'),
('2a024c0c-db36-4723-b5f5-fc27cea18d36', 'overnight-gap-down-trading-perpv1-24', 'trading', 'Overnight gap-down (trading)', 'A core position gaps down 57% overnight on an unverified headline. Your stop was set at -10% but the market never printed there, and the open is minutes away. There is no clean option.'),
('a239ba25-b49b-4d8d-b75e-c59e1730a283', 'the-leaked-number-negotiation-perpv1-25', 'negotiation', 'The leaked number (negotiation)', 'You now know, through a channel you should not have, roughly what the other side''s ceiling is. Using it tips your hand about how you know; not using it wastes real leverage.'),
('afe85aeb-7dcf-4df7-89ad-d6a91f1e978e', 'group-chat-archaeology-social-perpv1-26', 'social', 'Group chat archaeology (social)', 'Someone digs up an old message of yours and reads it in the worst possible light to the group. Context helps but sounds like an excuse.'),
('c1ef325d-96dd-44d0-a98d-ef0a3315231b', 'missing-teammate-crisis-perpv1-27', 'crisis', 'Missing teammate (crisis)', 'A key person has gone dark before a critical handoff and no one can reach them. Covering for them buys time; escalating exposes them.'),
('405296ff-2f61-4f19-9cb5-c4534ab73309', 'parabolic-breakout-trading-perpv1-28', 'trading', 'Parabolic breakout (trading)', 'A name you passed on is up 52% in three sessions and every feed is screaming about it. Sizing in now means chasing; sitting out means watching it run.'),
